def find_frames(n, m, grid):
    # Try all possible pairs of rectangles
    for r1a in range(n):
        for c1a in range(m):
            for r2a in range(r1a + 2, n):
                for c2a in range(c1a + 2, m):
                    if is_frame(grid, r1a, c1a, r2a, c2a):
                        # Found first frame, now look for second
                        for r1b in range(n):
                            for c1b in range(m):
                                for r2b in range(r1b + 2, n):
                                    for c2b in range(c1b + 2, m):
                                        if is_frame(grid, r1b, c1b, r2b, c2b):
                                            # Check if union of two frames covers all '#' cells
                                            covered = set()
                                            
                                            # Add cells from first frame border
                                            for r in range(r1a, r2a + 1):
                                                for c in range(c1a, c2a + 1):
                                                    if r == r1a or r == r2a or c == c1a or c == c2a:
                                                        covered.add((r, c))
                                            
                                            # Add cells from second frame border
                                            for r in range(r1b, r2b + 1):
                                                for c in range(c1b, c2b + 1):
                                                    if r == r1b or r == r2b or c == c1b or c == c2b:
                                                        covered.add((r, c))
                                            
                                            # Check if all '#' cells are covered and no extra '#' cells exist
                                            all_hash = set()
                                            for r in range(n):
                                                for c in range(m):
                                                    if grid[r][c] == '#':
                                                        all_hash.add((r, c))
                                            
                                            if covered == all_hash:
                                                return (True, (r1a + 1, c1a + 1, r2a + 1, c2a + 1), (r1b + 1, c1b + 1, r2b + 1, c2b + 1))
    
    return (False, None, None)

def solve(input_str):
    lines = input_str.strip().split('\n')
    n, m = map(int, lines[0].split())
    
    grid = []
    for i in range(1, n + 1):
        grid.append(list(lines[i]))
    
    found, frame1, frame2 = find_frames(n, m, grid)
    
    if found:
        result = "YES\n"
        result += f"{frame1[0]} {frame1[1]} {frame1[2]} {frame1[3]}\n"
        result += f"{frame2[0]} {frame2[1]} {frame2[2]} {frame2[3]}"
        return result
    else:
        return "NO"

